import{_ as t,o as e,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"ストーリー概要 — クトゥルフ神話テーマ","description":"","frontmatter":{},"headers":[],"relativePath":"ja/story/index.md","filePath":"ja/story/index.md","lastUpdated":1775394001000}'),s={name:"ja/story/index.md"};function i(n,a,d,o,h,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="ストーリー概要-—-クトゥルフ神話テーマ" tabindex="-1">ストーリー概要 — クトゥルフ神話テーマ <a class="header-anchor" href="#ストーリー概要-—-クトゥルフ神話テーマ" aria-label="Permalink to &quot;ストーリー概要 — クトゥルフ神話テーマ&quot;">​</a></h1><p>忘却前夜（Morimens）は**クトゥルフ神話（ラヴクラフト神話）**を世界観の基盤とした物語です。プレイヤーは覚醒体たちと共に、宇宙的恐怖（コズミックホラー）に満ちた世界で真実を追い求めます。</p><h2 id="世界設定" tabindex="-1">世界設定 <a class="header-anchor" href="#世界設定" aria-label="Permalink to &quot;世界設定&quot;">​</a></h2><p>人類の文明が発展する裏側で、太古より眠る旧支配者たちの力が目覚めつつあります。「覚醒体」と呼ばれる特殊な能力を持つ者たちは、界域の力を宿し、迫りくる忘却の夜に抗います。</p><h2 id="_4つの界域と神話的背景" tabindex="-1">4つの界域と神話的背景 <a class="header-anchor" href="#_4つの界域と神話的背景" aria-label="Permalink to &quot;4つの界域と神話的背景&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">界域</th><th style="text-align:left;">神話的モチーフ</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-chaos">混沌</span></td><td style="text-align:left;">ナイアルラトホテプ、アザトース — 狂気と混沌の外なる神</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">クトゥルフ、ダゴン — 深海に眠る旧支配者</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">シュブ＝ニグラス — 豊穣と肉体変容の暗黒母神</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">ヨグ＝ソトース — 時空を超越する全知の存在</td></tr></tbody></table><h2 id="ストーリー構成" tabindex="-1">ストーリー構成 <a class="header-anchor" href="#ストーリー構成" aria-label="Permalink to &quot;ストーリー構成&quot;">​</a></h2><ul><li><a href="./main.html">メインストーリー</a> — 本編のあらすじと章解説</li><li><a href="./character-stories.html">キャラクターストーリー</a> — 各覚醒体の個別エピソード</li><li><a href="./worldbuilding.html">世界観設定</a> — 世界設定の詳細</li><li><a href="./silver-core.html">銀芯通信</a> — ゲーム内読み物・設定資料</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>ストーリーはメインステージの進行に合わせて解放されます。キャラクターストーリーは各覚醒体の好感度を上げることで閲覧可能になります。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../stages/main.html">メインステージ</a></li><li><a href="./../awakeners/">覚醒体図鑑</a></li><li><a href="./../realms/">界域概要</a></li></ul>',11)])])}const f=t(s,[["render",i]]);export{p as __pageData,f as default};
